def git(*args):
    r = subprocess.run(["git", "-C", BASE] + list(args), capture_output=True, text=True)
    if r.returncode != 0:
        print(f"  git {' '.join(args)}: {r.stderr.strip()}")
    return r.returncode == 0


def push_with_retry():
    branch = subprocess.run(["git", "-C", BASE, "branch", "--show-current"],
                            capture_output=True, text=True).stdout.strip()
    for attempt in range(4):
        if git("push", "-u", "origin", branch):
            return True
        wait = 2 ** attempt
        print(f"  Push failed, retrying in {wait}s…")
        time.sleep(wait)
    return False


# ─── STEP 2: append new products to products.csv ──────────────────────────────
print("\n[STEP 2] Updating products.csv")
existing_slugs = set()
with open(PRODUCTS_CSV, "r", encoding="utf-8-sig") as f:
    reader = csv.reader(f)
    next(reader)
    for row in reader:
        if len(row) > 3:
            existing_slugs.add(row[3].strip())

new_products = [p for p in ALL_PRODUCTS if p["slug"] not in existing_slugs]
print(f"  New products to add: {len(new_products)}")

if new_products:
    with open(PRODUCTS_CSV, "a", newline="", encoding="utf-8") as f:
        writer = csv.writer(f)
        for p in new_products:
            url = f"https://www.producthunt.com/posts/{p['slug']}"
            writer.writerow([
                str(p["id"]), url, p["name"], p["slug"],
                p["description"], p["description"][:200],
                "0", "0",
                NOW, p["launch_date"], "new",
                "", "",
                NOW,
                "", "", "", "",
                NOW, NOW,
            ])
    print(f"  Written {len(new_products)} rows to products.csv")
    git("add", PRODUCTS_CSV)
    git("commit", "-m", f"Scrape {DATE}: added {len(new_products)} product(s)")
else:
    print("  No new products")

# ─── STEP 3: filter unanalyzed ────────────────────────────────────────────────
print("\n[STEP 3] Filtering unanalyzed products")
existing_analyzed = set()
with open(ANALYZED_CSV, "r", encoding="utf-8-sig") as f:
    reader = csv.reader(f)
    next(reader)
    for row in reader:
        if row and row[0].strip():
            existing_analyzed.add(row[0].strip())

unanalyzed = [p for p in ALL_PRODUCTS if str(p["id"]) not in existing_analyzed]
print(f"  Unanalyzed: {len(unanalyzed)}")

# ─── STEP 4: Pass 1 quick scoring ─────────────────────────────────────────────
print("\n[STEP 4] Pass 1 scoring")
passing = []
failing = []
for p in unanalyzed:
    opp, mkt, complexity = SCORES[p["id"]]
    if opp >= 6:
        passing.append(p)
        print(f"  PASS {p['id']} {p['name']} opp={opp} mkt={mkt}")
    else:
        failing.append(p)
        print(f"  FAIL {p['id']} {p['name']} opp={opp}")

print(f"  Passing: {len(passing)}  Failing: {len(failing)}")

# ─── Mark ALL scored in analyzed_ids.csv immediately ─────────────────────────
print("\n  Marking all scored IDs in analyzed_ids.csv")
with open(ANALYZED_CSV, "a", newline="", encoding="utf-8") as f:
    writer = csv.writer(f)
    for p in unanalyzed:
        writer.writerow([str(p["id"])] + [""] * 19)

git("add", ANALYZED_CSV)

# ─── STEP 5+6A: Full analysis + append analysis_history.csv ───────────────────
print("\n[STEP 5/6A] Writing full analyses to analysis_history.csv")
passing_ids = {p["id"] for p in passing}
new_analyses = [a for a in ANALYSES if a["product_id"] in passing_ids]
print(f"  Analyses to write: {len(new_analyses)}")

with open(HISTORY_CSV, "a", newline="", encoding="utf-8") as f:
    writer = csv.DictWriter(f, fieldnames=HISTORY_HEADERS, extrasaction="ignore")
    for a in new_analyses:
        writer.writerow(a)

print(f"  Done writing analysis_history.csv")

# ─── Commit analysis_history ──────────────────────────────────────────────────
git("add", HISTORY_CSV)
git("commit", "-m", f"Analysis {DATE}: {len(new_analyses)} product(s) analyzed")

# ─── Commit analyzed_ids ──────────────────────────────────────────────────────
git("add", ANALYZED_CSV)
git("commit", "-m", f"Mark {len(unanalyzed)} products as analyzed {DATE}")

